#include <vector>

class MedianFinder {
public:
    MedianFinder() {}

    void addNum(int num) {
        nums.push_back(num);
        sort(nums.begin(), nums.end());
        int size = nums.size();

        if (size % 2 == 0) {
            nums[size / 2] = num;
        } else {
            nums[size / 2] = num;
        }
    }

    double findMedian() {
        sort(nums.begin(), nums.end());
        int size = nums.size();

        if (size % 2 == 0) {
            return (nums[size / 2] + nums[size / 2 - 1]) / 2.0;
        } else {
            return nums[size / 2];
        }
    }
};
